const items = $input.all();
const result = [];
const now = new Date();

for (const item of items) {
  const props = item.json.properties || {};

  const dateFacture = props['Date']?.date?.start 
    || props['Date facture']?.date?.start
    || null;
  const prenomClient = props['Client']?.title?.[0]?.plain_text
    || props['Nom client']?.rich_text?.[0]?.plain_text
    || 'Client';
  const emailClient = props['Email']?.email
    || props['Email client']?.email
    || null;
  const montant = props['Montant']?.number
    || props['Total']?.number
    || 0;
  const numeroFacture = props['Numero']?.rich_text?.[0]?.plain_text
    || props['Reference']?.rich_text?.[0]?.plain_text
    || 'N/A';
  const pageId = item.json.id;

  if (!dateFacture || !emailClient) continue;

  const date = new Date(dateFacture);
  const diffJours = Math.floor((now - date) / (1000 * 60 * 60 * 24));

  if (diffJours >= 7 && diffJours < 8) {
    result.push({
      json: {
        typeRelance: 'J+7',
        pageId,
        prenomClient,
        emailClient,
        montant,
        numeroFacture,
        dateFacture,
        sujet: `Suivi — Facture #${numeroFacture}`,
        diffJours
      }
    });
  }

  if (diffJours >= 14 && diffJours < 15) {
    result.push({
      json: {
        typeRelance: 'J+14',
        pageId,
        prenomClient,
        emailClient,
        montant,
        numeroFacture,
        dateFacture,
        sujet: `URGENT — Facture #${numeroFacture} toujours en attente`,
        diffJours
      }
    });
  }
}

return result;
